import sys

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    A = list(map(int, data[1:N+1]))

    if all(a == 1 for a in A):
        print("Yes")
        return

    found = False

    # Check for pattern 'ARC' or 'CRA' in the sequence A
    for i in range(N):
        # Check for pattern 'ARC'
        if i + 2 < N:
            if A[i] == 0 and A[i+1] == 1 and A[i+2] == 1:
                found = True
                break
        else:
            # Wrap around
            if A[i] == 0 and A[i+1] == 1 and A[(i+2) % N] == 1:
                found = True
                break

        # Check for pattern 'CRA'
        if i + 2 < N:
            if A[i] == 1 and A[i+1] == 1 and A[i+2] == 0:
                found = True
                break
        else:
            if A[i] == 1 and A[i+1] == 1 and A[(i+2) % N] == 0:
                found = True
                break

    print("Yes" if found else "No")

if __name__ == "__main__":
    main()
